def solve(image, target_piece):
    # Assuming image is a 2D array and target_piece is a specific pattern to find
    rows = len(image)
    cols = len(image[0]) if rows > 0 else 0

    for i in range(rows):
        for j in range(cols):
            if image[i][j] == target_piece:
                return (i, j)  # Return the coordinates of the found piece
    return None
